final:
module RefModule (
    input wire rst_n,
    input wire clk,
    input wire en,
    input wire d,
    output reg q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        q <= 1'b0;
    else if (en)
        q <= d;
end

endmodule
